(()=>{let t=self;t.addEventListener("push",e=>{let i;if(!e.data)return;try{i=e.data.json()}catch{return}let n=i?.title??"Work Log Reminder",o=i?.body??"Time to log your work",l=i?.url??"/home";e.waitUntil(t.registration.showNotification(n,{body:o,icon:"/icon-192x192.png",badge:"/icon-192x192.png",data:{url:l},tag:"work-log-reminder",renotify:!0}))}),t.addEventListener("notificationclick",e=>{e.notification.close();let i=e.notification.data?.url??"/home";e.waitUntil(t.clients.matchAll({type:"window",includeUncontrolled:!0}).then(e=>{if(e.length>0){let t=e[0];t.navigate(i),t.focus()}else t.clients.openWindow&&t.clients.openWindow(i)}))})})();